        ACTIVE,
        EXECUTED,
        CANCELLED,
        EXPIRED,
        FAILED
    }

    // Condition types for triggers
    enum ConditionType {
        PRICE_ABOVE,
        PRICE_BELOW,
        PRICE_CHANGE_PERCENT,
        TIME_BASED,
        VOLUME_THRESHOLD,
        LIQUIDITY_THRESHOLD,
        YIELD_THRESHOLD,
        CUSTOM_LOGIC
