// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title ISmartAccount
 * @dev Interface for Smart Account contract
 */
interface ISmartAccount {
    /**
     * @dev Executes a transaction
     * @param dest Destination address
     * @param value ETH value to send
     * @param func Function call data
     */
    function execute(
        address dest,
        uint256 value,
        bytes calldata func
    ) external;

    /**
     * @dev Executes multiple transactions in batch
     * @param dest Array of destination addresses
     * @param value Array of ETH values to send
     * @param func Array of function call data
     */
    function executeBatch(
        address[] calldata dest,
        uint256[] calldata value,
        bytes[] calldata func
    ) external;

    /**
     * @dev Executes an automated operation using session key
     * @param dest Destination address
     * @param value ETH value to send
     * @param func Function call data
     * @param sessionKey Session key that should execute this
     */
    function executeAutomated(
        address dest,
        uint256 value,
        bytes calldata func,
        address sessionKey
    ) external;

    /**
     * @dev Returns the owner of the Smart Account
     */
    function owner() external view returns (address);

    /**
     * @dev Returns the current nonce for this account
     */
    function getNonce() external view returns (uint256);

    /**
     * @dev Creates a new session key for automation
     * @param sessionKey Address of the session key
     * @param validUntil Expiration timestamp
     * @param limitAmount Maximum amount this key can spend
     * @param allowedTargets Allowed contract addresses
     * @param allowedFunctions Allowed function selectors
     */
    function createSessionKey(
        address sessionKey,
        uint256 validUntil,
        uint256 limitAmount,
        address[] calldata allowedTargets,
        bytes4[] calldata allowedFunctions
    ) external;

    /**
     * @dev Revokes a session key
     * @param sessionKey Session key to revoke
     */
    function revokeSessionKey(address sessionKey) external;

    /**
     * @dev Adds a guardian for emergency recovery
     * @param guardian Guardian address to add
     */
    function addGuardian(address guardian) external;

    /**
     * @dev Removes a guardian
     * @param guardian Guardian address to remove
     */
    function removeGuardian(address guardian) external;

    /**
     * @dev Emergency recovery function (requires guardian signatures)
     * @param newOwner New owner address
     * @param guardianAddresses Array of guardian addresses
     * @param guardianSignatures Array of guardian signatures
     */
    function emergencyRecovery(
        address newOwner,
        address[] calldata guardianAddresses,
        bytes[] calldata guardianSignatures
    ) external;
}

contracts/SessionKeyManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

/**
 * @title SessionKeyManager
 * @dev Manages session keys for Smart Accounts with permission-based automation
 * @notice Session keys enable secure automation without exposing main private keys
 */
contract SessionKeyManager is Ownable, ReentrancyGuard {
    constructor() Ownable(msg.sender) {}
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    // Session key data structure
    struct SessionKey {
        bool isActive;
        uint256 validUntil;
        uint256 limitAmount;
        uint256 spentAmount;
        uint256 usageCount;
        uint256 maxUsageCount;
        address[] allowedTargets;
        bytes4[] allowedFunctions;
        uint256 createdAt;
        uint256 lastUsedAt;
    }

    // Mapping: sessionKey => smartAccount => SessionKey data
    mapping(address => mapping(address => SessionKey)) public sessionKeys;

    // Mapping: smartAccount => sessionKey[]
    mapping(address => address[]) public accountSessionKeys;

    // Mapping: sessionKey => smartAccount[] (for batch operations)
    mapping(address => address[]) public sessionKeyAccounts;

    // Events
    event SessionKeyCreated(
        address indexed sessionKey,
        address indexed smartAccount,
        uint256 validUntil,
        uint256 limitAmount
    );

    event SessionKeyRevoked(
        address indexed sessionKey,
        address indexed smartAccount
    );

    event SessionKeyUsed(
        address indexed sessionKey,
        address indexed smartAccount,
        address target,
        uint256 amount
    );

    event AllSessionKeysRevoked(address indexed smartAccount);

    /**
     * @dev Creates a new session key for a Smart Account
     * @param sessionKey Address of the session key
     * @param smartAccount Address of the Smart Account
     * @param validUntil Expiration timestamp
     * @param limitAmount Maximum amount this key can spend (in wei)
     * @param allowedTargets Allowed contract addresses
     * @param allowedFunctions Allowed function selectors
     */
    function createSessionKey(
        address sessionKey,
        address smartAccount,
        uint256 validUntil,
        uint256 limitAmount,
        address[] calldata allowedTargets,
        bytes4[] calldata allowedFunctions
    ) external onlyOwner {
        require(smartAccount == owner(), "SessionKeyManager: Smart account mismatch");
        require(sessionKey != address(0), "SessionKeyManager: Invalid session key");
        require(validUntil > block.timestamp, "SessionKeyManager: Invalid expiration");
        require(limitAmount > 0, "SessionKeyManager: Invalid limit amount");
        require(allowedTargets.length > 0, "SessionKeyManager: No allowed targets");
        require(allowedFunctions.length > 0, "SessionKeyManager: No allowed functions");

        for (uint256 i = 0; i < allowedTargets.length; i++) {
            require(allowedTargets[i] != address(0), "SessionKeyManager: Invalid target");
        }

        // Ensure session key doesn't already exist for this account
        require(
            !sessionKeys[sessionKey][smartAccount].isActive,
            "SessionKeyManager: Session key already exists"
        );

        // Store session key data
        sessionKeys[sessionKey][smartAccount] = SessionKey({
            isActive: true,
            validUntil: validUntil,
            limitAmount: limitAmount,
            spentAmount: 0,
            usageCount: 0,
            maxUsageCount: 1000, // Default max usage
            allowedTargets: allowedTargets,
            allowedFunctions: allowedFunctions,
            createdAt: block.timestamp,
            lastUsedAt: 0
        });

        // Add to tracking arrays
        accountSessionKeys[smartAccount].push(sessionKey);
        sessionKeyAccounts[sessionKey].push(smartAccount);

        emit SessionKeyCreated(sessionKey, smartAccount, validUntil, limitAmount);
    }

    /**
     * @dev Revokes a session key for a specific Smart Account
     * @param sessionKey Session key to revoke
     * @param smartAccount Smart Account address
     */
    function revokeSessionKey(address sessionKey, address smartAccount) external onlyOwner {
        require(smartAccount == owner(), "SessionKeyManager: Smart account mismatch");
        require(
            sessionKeys[sessionKey][smartAccount].isActive,
            "SessionKeyManager: Session key not active"
        );

        sessionKeys[sessionKey][smartAccount].isActive = false;

        // Remove from tracking arrays
        _removeFromArray(accountSessionKeys[smartAccount], sessionKey);
        _removeFromArray(sessionKeyAccounts[sessionKey], smartAccount);

        emit SessionKeyRevoked(sessionKey, smartAccount);
    }

    /**
     * @dev Revokes all session keys for a Smart Account (emergency function)
     * @param smartAccount Smart Account address
     */
    function revokeAllSessionKeys(address smartAccount) external onlyOwner {
        require(smartAccount == owner(), "SessionKeyManager: Smart account mismatch");
        address[] memory keys = accountSessionKeys[smartAccount];

        for (uint256 i = 0; i < keys.length; i++) {
            if (sessionKeys[keys[i]][smartAccount].isActive) {
                sessionKeys[keys[i]][smartAccount].isActive = false;
                _removeFromArray(sessionKeyAccounts[keys[i]], smartAccount);
            }
        }

        // Clear the array
        delete accountSessionKeys[smartAccount];

        emit AllSessionKeysRevoked(smartAccount);
    }

    /**
     * @dev Checks if a session key is valid for a Smart Account
     * @param sessionKey Session key address
     * @param smartAccount Smart Account address
     * @return True if valid
     */
    function isValidSessionKey(address sessionKey, address smartAccount) 
        external 
        view 
        returns (bool) 
    {
        SessionKey storage key = sessionKeys[sessionKey][smartAccount];

        return key.isActive && 
               block.timestamp <= key.validUntil &&
               key.usageCount < key.maxUsageCount;
    }

    /**
     * @dev Checks if a session key can execute a specific operation
     * @param smartAccount Smart Account address requesting execution
     * @param target Target contract address
     * @param callData Call data containing function selector
     * @return True if operation is allowed
     */
    function canExecute(
        address sessionKey,
        address smartAccount,
        address target,
        bytes calldata callData
    ) external view returns (bool) {
        SessionKey storage key = sessionKeys[sessionKey][smartAccount];

        if (!key.isActive || block.timestamp > key.validUntil) {
            return false;
        }

        // Check if target is allowed
        bool targetAllowed = false;
        for (uint256 i = 0; i < key.allowedTargets.length; i++) {
            if (key.allowedTargets[i] == target) {
                targetAllowed = true;
                break;
            }
        }

        if (!targetAllowed) {
            return false;
        }

        // Check if function is allowed
        if (callData.length < 4) {
            return false;
        }

        bytes4 functionSelector = bytes4(callData[:4]);
        bool functionAllowed = false;

        for (uint256 i = 0; i < key.allowedFunctions.length; i++) {
            if (key.allowedFunctions[i] == functionSelector) {
                functionAllowed = true;
                break;
            }
        }

        return functionAllowed;
    }

    /**
     * @dev Validates a session key signature for user operations
     * @param sessionKey Session key that signed
     * @param smartAccount Smart Account address
     * @param callData Operation call data
     * @param signature The signature to validate
     * @return True if signature is valid
     */
    function validateSessionKeySignature(
        address sessionKey,
        address smartAccount,
        bytes calldata callData,
        bytes calldata signature
    ) external view returns (bool) {
        if (!this.isValidSessionKey(sessionKey, smartAccount)) {
            return false;
        }

        // Create message hash
        bytes32 messageHash = keccak256(
            abi.encodePacked(smartAccount, callData, block.chainid)
        ).toEthSignedMessageHash();

        // Recover signer
        address recovered = messageHash.recover(signature);

        return recovered == sessionKey;
    }

    /**
     * @dev Updates session key usage statistics
     * @param sessionKey Session key address
     */
    function updateUsage(address sessionKey) external onlyOwner {
        // Find the smart account for this session key (caller should be smart account)
        SessionKey storage key = sessionKeys[sessionKey][msg.sender];

        require(key.isActive, "SessionKeyManager: Session key not active");

        key.usageCount++;
        key.lastUsedAt = block.timestamp;

        emit SessionKeyUsed(sessionKey, msg.sender, address(0), 0);
    }

    /**
     * @dev Updates spending amount for a session key
     * @param sessionKey Session key address
     * @param amount Amount spent
     */
    function updateSpending(address sessionKey, uint256 amount) external onlyOwner {
        SessionKey storage key = sessionKeys[sessionKey][msg.sender];

        require(key.isActive, "SessionKeyManager: Session key not active");
        require(
            key.spentAmount + amount <= key.limitAmount,
            "SessionKeyManager: Spending limit exceeded"
        );

        key.spentAmount += amount;

        emit SessionKeyUsed(sessionKey, msg.sender, address(0), amount);
    }

    /**
     * @dev Ownership of the manager is permanently bound to the Smart Account
     */
    function transferOwnership(address) public view override onlyOwner {
        revert("SessionKeyManager: Ownership cannot be transferred");
    }

    /**
     * @dev Prevent accidental renounce of ownership
     */
    function renounceOwnership() public view override onlyOwner {
        revert("SessionKeyManager: Ownership cannot be renounced");
    }

    /**
     * @dev Gets session key data
     * @param sessionKey Session key address
     * @param smartAccount Smart Account address
     * @return isActive Whether the session key is active
     * @return validUntil Expiration timestamp
     * @return limitAmount Maximum spending limit
     * @return spentAmount Amount already spent
     * @return usageCount Number of times used
     * @return allowedTargets Allowed contract addresses
     * @return allowedFunctions Allowed function selectors
     */
    function getSessionKey(address sessionKey, address smartAccount) 
        external 
        view 
        returns (
            bool isActive,
            uint256 validUntil,
            uint256 limitAmount,
            uint256 spentAmount,
            uint256 usageCount,
            address[] memory allowedTargets,
            bytes4[] memory allowedFunctions
        ) 
    {
        SessionKey storage key = sessionKeys[sessionKey][smartAccount];

        return (
            key.isActive,
            key.validUntil,
            key.limitAmount,
            key.spentAmount,
            key.usageCount,
            key.allowedTargets,
            key.allowedFunctions
        );
    }

    /**
     * @dev Gets all session keys for a Smart Account
     * @param smartAccount Smart Account address
     * @return Array of session key addresses
     */
    function getAccountSessionKeys(address smartAccount) 
        external 
        view 
        returns (address[] memory) 
    {
        return accountSessionKeys[smartAccount];
    }

    /**
     * @dev Gets session key statistics
     * @param sessionKey Session key address
     * @param smartAccount Smart Account address
     * @return createdAt lastUsedAt usageCount spentAmount
     */
    function getSessionKeyStats(address sessionKey, address smartAccount)
        external
        view
        returns (uint256 createdAt, uint256 lastUsedAt, uint256 usageCount, uint256 spentAmount)
    {
        SessionKey storage key = sessionKeys[sessionKey][smartAccount];
        return (key.createdAt, key.lastUsedAt, key.usageCount, key.spentAmount);
    }

    /**
     * @dev Internal function to remove address from array
     * @param array Array to modify
     * @param addr Address to remove
     */
    function _removeFromArray(address[] storage array, address addr) internal {
        for (uint256 i = 0; i < array.length; i++) {
            if (array[i] == addr) {
                array[i] = array[array.length - 1];
                array.pop();
                break;
            }
        }
    }

    /**
     * @dev Emergency pause function (only owner)
     */
    function pause() external onlyOwner {
        // Implementation would pause all operations
    }

    /**
     * @dev Emergency unpause function (only owner)
     */
    function unpause() external onlyOwner {
        // Implementation would resume operations
    }
}

contracts/SmartAccount.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@account-abstraction/contracts/core/BaseAccount.sol";
import "@account-abstraction/contracts/samples/callback/TokenCallbackHandler.sol";
import "@account-abstraction/contracts/interfaces/PackedUserOperation.sol";
import "@account-abstraction/contracts/interfaces/IEntryPoint.sol";
import "@openzeppelin/contracts/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts/proxy/utils/UUPSUpgradeable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";
import "./SessionKeyManager.sol";
import "./interfaces/ISmartAccount.sol";

/**
 * @title SmartAccount
 * @dev ERC-4337 compatible Smart Account with session key support for DeFi automation
 * @notice This contract allows users to automate DeFi operations without exposing private keys
 */
contract SmartAccount is
    ISmartAccount,
    BaseAccount,
    TokenCallbackHandler,
    UUPSUpgradeable,
    Initializable,
    ReentrancyGuard
{
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    // State variables
    address private _owner;
    SessionKeyManager public sessionKeyManager;
    uint256 private _nonce;

    // Emergency recovery
    mapping(address => bool) public guardians;
    uint256 public guardiansCount;
    uint256 public recoveryThreshold;

    // Execution tracking
    mapping(bytes32 => bool) public executedOperations;

    // Events
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event GuardianAdded(address indexed guardian);
    event GuardianRemoved(address indexed guardian);
    event EmergencyRecovery(address indexed newOwner, address[] guardians);
    event OperationExecuted(bytes32 indexed operationHash, bool success);

    // Modifiers
    modifier onlyOwnerOrSessionKey() {
        require(
            msg.sender == _owner || 
            sessionKeyManager.isValidSessionKey(msg.sender, address(this)),
            "SmartAccount: Not authorized"
        );
        _;
    }

    modifier onlyOwnerOrEntryPoint() {
        require(
            msg.sender == _owner || msg.sender == address(entryPoint()),
            "SmartAccount: Not owner or EntryPoint"
        );
        _;
    }

    IEntryPoint private immutable _entryPoint;

    constructor(IEntryPoint anEntryPoint) {
        _entryPoint = anEntryPoint;
        _disableInitializers();
    }

    function entryPoint() public view virtual override returns (IEntryPoint) {
        return _entryPoint;
    }

    /**
     * @dev Initializer function (called by factory)
     * @param anOwner The owner of this Smart Account
     */
    function initialize(address anOwner) public initializer {
        require(anOwner != address(0), "SmartAccount: Invalid owner");

        _owner = anOwner;

        // Deploy session key manager
        sessionKeyManager = new SessionKeyManager();

        // Set up emergency recovery (2 of 3 threshold)
        recoveryThreshold = 2;

        emit OwnershipTransferred(address(0), anOwner);
    }

    /**
     * @dev Returns the owner of the Smart Account
     */
    function owner() public view returns (address) {
        return _owner;
    }

    /**
     * @dev Returns the current nonce for this account
     */
    function getNonce() public view override(BaseAccount, ISmartAccount) returns (uint256) {
        return entryPoint().getNonce(address(this), 0);
    }

    /**
     * @dev Validates a user operation signature
     * @param userOp The user operation to validate
     * @param userOpHash Hash of the user operation
     * @return validationData Validation result (0 for success)
     */
    function _validateSignature(
        PackedUserOperation calldata userOp,
        bytes32 userOpHash
    ) internal view override returns (uint256 validationData) {
        bytes32 hash = userOpHash.toEthSignedMessageHash();

        // Try owner signature first
        address recovered = hash.recover(userOp.signature);
        if (recovered == _owner) {
            return 0; // Success
        }

        // Check session key signatures
        if (sessionKeyManager.validateSessionKeySignature(
            recovered,
            address(this),
            userOp.callData,
            userOp.signature
        )) {
            return 0; // Success
        }

        return 1; // SIG_VALIDATION_FAILED
    }

    /**
     * @dev Executes a transaction (called by EntryPoint or owner)
     * @param dest Destination address
     * @param value ETH value to send
     * @param func Function call data
     */
    function execute(
        address dest,
        uint256 value,
        bytes calldata func
    ) external onlyOwnerOrEntryPoint nonReentrant {
        _call(dest, value, func);
    }

    /**
     * @dev Executes multiple transactions in batch
     * @param dest Array of destination addresses
     * @param value Array of ETH values to send
     * @param func Array of function call data
     */
    function executeBatch(
        address[] calldata dest,
        uint256[] calldata value,
        bytes[] calldata func
    ) external onlyOwnerOrEntryPoint nonReentrant {
        require(
            dest.length == func.length && 
            (value.length == 0 || value.length == func.length),
            "SmartAccount: Array length mismatch"
        );

        for (uint256 i = 0; i < dest.length; i++) {
            _call(dest[i], value.length == 0 ? 0 : value[i], func[i]);
        }
    }

    /**
     * @dev Executes an automated operation using session key
     * @param dest Destination address
     * @param value ETH value to send
     * @param func Function call data
     * @param sessionKey Session key that should execute this
     */
    function executeAutomated(
        address dest,
        uint256 value,
        bytes calldata func,
        address sessionKey
    ) external nonReentrant {
        bool callerIsSessionKey = msg.sender == sessionKey;
        bool callerIsEntryPoint = msg.sender == address(entryPoint());
        require(
            callerIsSessionKey || callerIsEntryPoint,
            "SmartAccount: Caller not authorized"
        );

        require(
            sessionKeyManager.isValidSessionKey(sessionKey, address(this)),
            "SmartAccount: Invalid session key"
        );

        require(
            sessionKeyManager.canExecute(sessionKey, address(this), dest, func),
            "SmartAccount: Session key cannot execute this operation"
        );

        // Create operation hash for tracking
        bytes32 operationHash = keccak256(
            abi.encodePacked(dest, value, func, block.timestamp)
        );

        require(!executedOperations[operationHash], "SmartAccount: Operation already executed");
        executedOperations[operationHash] = true;

        bool success = _call(dest, value, func);
        require(success, "SmartAccount: Automated call failed");

        // Update session key usage
        if (value > 0) {
            sessionKeyManager.updateSpending(sessionKey, value);
        }
        sessionKeyManager.updateUsage(sessionKey);

        emit OperationExecuted(operationHash, success);
    }

    /**
     * @dev Creates a new session key for automation
     * @param sessionKey Address of the session key
     * @param validUntil Expiration timestamp
     * @param limitAmount Maximum amount this key can spend
     * @param allowedTargets Allowed contract addresses
     * @param allowedFunctions Allowed function selectors
     */
    function createSessionKey(
        address sessionKey,
        uint256 validUntil,
        uint256 limitAmount,
        address[] calldata allowedTargets,
        bytes4[] calldata allowedFunctions
    ) external {
        require(msg.sender == _owner, "SmartAccount: Only owner can create session keys");

        sessionKeyManager.createSessionKey(
            sessionKey,
            address(this),
            validUntil,
            limitAmount,
            allowedTargets,
            allowedFunctions
        );
    }

    /**
     * @dev Revokes a session key
     * @param sessionKey Session key to revoke
     */
    function revokeSessionKey(address sessionKey) external {
        require(msg.sender == _owner, "SmartAccount: Only owner can revoke session keys");
        sessionKeyManager.revokeSessionKey(sessionKey, address(this));
    }

    /**
     * @dev Adds a guardian for emergency recovery
     * @param guardian Guardian address to add
     */
    function addGuardian(address guardian) external {
        require(msg.sender == _owner, "SmartAccount: Only owner");
        require(guardian != address(0) && guardian != _owner, "SmartAccount: Invalid guardian");
        require(!guardians[guardian], "SmartAccount: Guardian already exists");

        guardians[guardian] = true;
        guardiansCount++;

        emit GuardianAdded(guardian);
    }

    /**
     * @dev Removes a guardian
     * @param guardian Guardian address to remove
     */
    function removeGuardian(address guardian) external {
        require(msg.sender == _owner, "SmartAccount: Only owner");
        require(guardians[guardian], "SmartAccount: Guardian does not exist");

        guardians[guardian] = false;
        guardiansCount--;

        emit GuardianRemoved(guardian);
    }

    /**
     * @dev Emergency recovery function (requires guardian signatures)
     * @param newOwner New owner address
     * @param guardianSignatures Array of guardian signatures
     */
    function emergencyRecovery(
        address newOwner,
        address[] calldata guardianAddresses,
        bytes[] calldata guardianSignatures
    ) external {
        require(newOwner != address(0), "SmartAccount: Invalid new owner");
        require(
            guardianAddresses.length >= recoveryThreshold,
            "SmartAccount: Insufficient guardians"
        );
        require(
            guardianAddresses.length == guardianSignatures.length,
            "SmartAccount: Array length mismatch"
        );

        bytes32 hash = keccak256(
            abi.encodePacked("EMERGENCY_RECOVERY", newOwner, address(this))
        ).toEthSignedMessageHash();

        uint256 validSignatures = 0;

        for (uint256 i = 0; i < guardianAddresses.length; i++) {
            address guardian = guardianAddresses[i];

            require(guardians[guardian], "SmartAccount: Not a guardian");

            // Check for duplicates in the submitted array
            for (uint256 j = 0; j < i; j++) {
                require(guardianAddresses[j] != guardian, "SmartAccount: Duplicate guardian");
            }

            address recovered = hash.recover(guardianSignatures[i]);
            if (recovered == guardian) {
                validSignatures++;
            }
        }

        require(
            validSignatures >= recoveryThreshold,
            "SmartAccount: Insufficient valid signatures"
        );

        address oldOwner = _owner;
        _owner = newOwner;

        // Revoke all session keys on recovery
        sessionKeyManager.revokeAllSessionKeys(address(this));

        emit EmergencyRecovery(newOwner, guardianAddresses);
        emit OwnershipTransferred(oldOwner, newOwner);
    }

    /**
     * @dev Internal function to execute a call
     * @param target Target address
     * @param value ETH value
     * @param data Call data
     * @return success Whether the call succeeded
     */
    function _call(address target, uint256 value, bytes memory data) internal returns (bool success) {
        assembly {
            success := call(gas(), target, value, add(data, 0x20), mload(data), 0, 0)
        }
    }

    /**
     * @dev UUPS upgrade authorization
     * @param newImplementation New implementation address
     */
    function _authorizeUpgrade(address newImplementation) internal view override {
        require(msg.sender == _owner, "SmartAccount: Only owner can upgrade");
        (newImplementation); // Silence unused variable warning
    }

    /**
     * @dev Receives ETH
     */
    receive() external payable {}

    /**
     * @dev Fallback function
     */
    fallback() external payable {}
}
